var TaskerUtils = Class.create();
TaskerUtils.prototype = {
	initialize: function() {
	},

	Catch: function(context, e) {
		gs.error("Tasker | " + context + ": " + e.message);
		gs.error('LineNumber :' + e.lineNumber);
		gs.error('SourceName :' + e.sourceName);
		gs.error('Name: ' + e.name);
		gs.error('Message : ' + e.message);
	},

	type: 'TaskerUtils'
};
